import { useAddArrayIndex } from ':components/Select/components/hooks/useAddArrayIndex';
import { useSelectKeyBoardNavigation } from ':components/Select/components/hooks/useSelectKeyBoardNavigation';
import { getCheckboxStatus, getPreparedOptions } from ':components/Select/helpers';
import type { Option } from ':components/Select/Select.types';
import { getBEMClasses } from ':helpers/get-bem';
import { shallowEqual } from ':helpers/shallowEqual';
import { useCallback, useRef, useState } from 'react';

import { CheckboxType } from './Chip.types';

interface UseChipLogicProps<T> {
	isOpen?: boolean;
	isSelectMode?: boolean;
	onOpen?: () => void;
	onClose?: () => void;
	options?: T[];
	values?: T[];
	onOutsideClick?: (event: MouseEvent) => void;
	onSelect?: (values: T[], changedItem?: T) => void;
	enableKeyboardNavigation?: boolean;
	multiple?: boolean;
	selectAll?: boolean;
	filter?: boolean;
	filterFunction?: (options: Array<Option<T>>, filterValue: string) => Array<Option<T>>;
}

const [selectClassName, , selectElement] = getBEMClasses('dsb__select');
const [optionsClassName, , optionsElement] = selectElement('options');
const [itemClassName] = optionsElement('item');

export const useChip = <T,>(props: UseChipLogicProps<T>) => {
	const {
		isOpen,
		options,
		values,
		isSelectMode,
		onOpen,
		onClose,
		onOutsideClick,
		onSelect,
		filter,
		filterFunction,
		enableKeyboardNavigation,
		multiple,
		selectAll,
	} = props;

	const chipRef = useRef<HTMLButtonElement>(null);
	const filterRef = useRef<HTMLInputElement>(null);
	const selectRef = useRef<HTMLDivElement>(null);
	const optionsRef = useRef<HTMLDivElement>(null);

	const [dropdownOpen, setDropdownOpen] = useState(isOpen);
	const [filterValue, setFilterValue] = useState('');

	const [privateOptions, privateValues] = useAddArrayIndex({ options, values });

	const handleOpen = () => {
		if (!isSelectMode) {
			return;
		}

		setDropdownOpen(true);
		onOpen?.();
	};

	const handleClose = useCallback((): void => {
		setDropdownOpen(false);
		onClose?.();
	}, [onClose, setDropdownOpen]);

	const handleClickOutside = (event: MouseEvent) => {
		if (!chipRef.current || chipRef.current.contains(event.target as Node)) {
			return;
		}

		handleClose();
		onOutsideClick?.(event);
	};

	const onSelectItem = (item: Option<T>) => () => {
		onSelect?.([item.value]);
		handleClose();
	};

	const onMultiselectItem = (item: Option<T>) => () => {
		const itemIndex = privateValues.findIndex(value => item.id === value.id);
		const isAddition = itemIndex === -1;
		const updItems = isAddition ? [...privateValues, item] : privateValues.filter((_value, i) => itemIndex !== i);
		const userValues = updItems.map(item => item.value);
		onSelect(userValues, item.value);
	};

	const [focusedIndex] = useSelectKeyBoardNavigation({
		enableKeyboardNavigation,
		options: privateOptions,
		handleClose,
		multiple,
		optionsRef,
		onMultiselectItem,
		onSelectItem,
		selectAll,
	});

	const handleSelectAll = () => {
		const filteredOptions = getPreparedOptions(privateOptions, filter, filterValue, filterFunction);
		const isChecked = getSelectAllStatus() === CheckboxType.CHECKED;

		const checkedFilterFunction = val => !filteredOptions.some(opt => shallowEqual(opt.value, val.value));
		const filterOptionsFunction = val => !privateValues.some(opt => shallowEqual(opt.value, val.value));

		const updatedValues = isChecked
			? privateValues.filter(checkedFilterFunction)
			: [...privateValues, ...filteredOptions.filter(filterOptionsFunction)];

		onSelect(updatedValues.map(item => item.value));
	};

	const getSelectAllStatus = (): CheckboxType =>
		getCheckboxStatus(privateOptions, privateValues, filterValue, filter, filterFunction);

	const changeFilterValue = (value: string): void => {
		setFilterValue(value.trim());
	};

	return {
		chipRef,
		dropdownOpen,
		setDropdownOpen,
		handleClickOutside,
		selectClassName,
		privateValues,
		privateOptions,
		filterValue,
		optionsClassName,
		itemClassName,
		onMultiselectItem,
		onSelectItem,
		focusedIndex,
		handleSelectAll,
		optionsRef,
		getSelectAllStatus,
		filterRef,
		changeFilterValue,
		selectRef,
		handleOpen,
	};
};
